import{_ as t,a,b as o}from"./chunks/jumbo2.BkRIXxbD.js";import{c as r,Q as n,j as i,m as c}from"./chunks/framework.rlpw0eGz.js";const v=JSON.parse('{"title":"Advanced Settings for OpenIPC","description":"Detailed guide for Jumbo frame, overheating protection and advanced configuration.","frontmatter":{"title":"Advanced Settings for OpenIPC","description":"Detailed guide for Jumbo frame, overheating protection and advanced configuration.","head":[["link",{"rel":"canonical","href":"https://openfpv.com.ua/en/configuration/advanced"}],["link",{"rel":"alternate","hreflang":"uk","href":"https://openfpv.com.ua/configuration/advanced"}],["link",{"rel":"alternate","hreflang":"en","href":"https://openfpv.com.ua/en/configuration/advanced"}],["link",{"rel":"alternate","hreflang":"x-default","href":"https://openfpv.com.ua/configuration/advanced"}],["meta",{"property":"og:type","content":"article"}],["meta",{"property":"og:url","content":"https://openfpv.com.ua/en/configuration/advanced"}],["meta",{"property":"og:title","content":"Advanced Settings for OpenIPC"}],["meta",{"property":"og:description","content":"Detailed guide for Jumbo frame, overheating protection and advanced configuration."}],["meta",{"property":"og:image","content":"https://openfpv.com.ua/og-config.png"}],["meta",{"property":"og:locale","content":"en_US"}],["meta",{"property":"og:locale:alternate","content":"uk_UA"}],["meta",{"name":"twitter:image","content":"https://openfpv.com.ua/og-config.png"}],["meta",{"name":"twitter:title","content":"Advanced Settings for OpenIPC"}],["meta",{"name":"twitter:description","content":"Detailed guide for Jumbo frame, overheating protection and advanced configuration."}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@graph\\":[{\\"@type\\":\\"Organization\\",\\"@id\\":\\"https://openfpv.com.ua/#org\\",\\"name\\":\\"OpenFPV Ukraine\\",\\"url\\":\\"https://openfpv.com.ua\\",\\"logo\\":\\"https://openfpv.com.ua/logo-light.png\\",\\"sameAs\\":[\\"https://github.com/Maxwell456/openipc-docs-ukr\\"]},{\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://openfpv.com.ua/en/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Configuration\\",\\"item\\":\\"https://openfpv.com.ua/en/configuration/multiconfigurator\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Advanced Settings for OpenIPC\\"}]},{\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Advanced Settings for OpenIPC\\",\\"description\\":\\"Detailed guide for Jumbo frame, overheating protection and advanced configuration.\\",\\"inLanguage\\":\\"en-US\\",\\"url\\":\\"https://openfpv.com.ua/en/configuration/advanced\\",\\"image\\":\\"https://openfpv.com.ua/og-config.png\\",\\"dateModified\\":\\"2026-05-31T11:48:56.000Z\\",\\"author\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"},\\"publisher\\":{\\"@id\\":\\"https://openfpv.com.ua/#org\\"}}]}"]]},"headers":[],"relativePath":"en/configuration/advanced.md","filePath":"en/configuration/advanced.md","lastUpdated":1780228136000}'),d={name:"en/configuration/advanced.md"};function p(s,e,l,h,m,u){return n(),i("div",null,[...e[0]||(e[0]=[c('<h1 id="advanced-settings-for-openipc" tabindex="-1">Advanced Settings for OpenIPC <a class="header-anchor" href="#advanced-settings-for-openipc" aria-label="Permalink to &quot;Advanced Settings for OpenIPC&quot;">​</a></h1><h2 id="🛜-jumbo-frame-50-mbit" tabindex="-1">🛜 Jumbo Frame 50 Mbit <a class="header-anchor" href="#🛜-jumbo-frame-50-mbit" aria-label="Permalink to &quot;🛜 Jumbo Frame 50 Mbit&quot;">​</a></h2><p><strong>Jumbo frame</strong> is an Ethernet packet whose size <strong>exceeds the standard 1500 bytes (MTU)</strong>. These packets are typically <strong>up to 9000 bytes</strong>.</p><blockquote><p>This feature allows <strong>more data to be transferred at once</strong>, reducing the number of individual packets and improving network performance.</p></blockquote><hr><h2 id="why-use-it" tabindex="-1">Why Use It? <a class="header-anchor" href="#why-use-it" aria-label="Permalink to &quot;Why Use It?&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Benefit</th><th>Explanation</th></tr></thead><tbody><tr><td>✅ Lower CPU load</td><td>Fewer packets = less processing</td></tr><tr><td>✅ Higher data throughput</td><td>Ideal for <strong>high-bandwidth streams</strong>: video, FPV.</td></tr><tr><td>✅ Lower latency</td><td>More stable link, less processing time per packet</td></tr></tbody></table><hr><div class="warning custom-block"><p class="custom-block-title">Note!</p><p>Jumbo frame only works <strong>if all devices on the network support</strong> large packets (camera and VRX with firmware 1.9.9+)</p></div><hr><h2 id="jumbo-frame-setup-guide" tabindex="-1">Jumbo Frame Setup Guide <a class="header-anchor" href="#jumbo-frame-setup-guide" aria-label="Permalink to &quot;Jumbo Frame Setup Guide&quot;">​</a></h2><h3 id="_1-download-openipc-configurator-mario" tabindex="-1">1. Download OpenIPC Configurator Mario <a class="header-anchor" href="#_1-download-openipc-configurator-mario" aria-label="Permalink to &quot;1. Download OpenIPC Configurator Mario&quot;">​</a></h3><p>Download the <strong>unofficial</strong> <a href="https://github.com/OpenIPC/configurator/releases" target="_blank" rel="noreferrer">OpenIPC Configurator</a></p><blockquote><p>This tool allows flexible configuration of network parameters, image settings and firmware updates.</p></blockquote><hr><h3 id="_2-update-the-firmware" tabindex="-1">2. Update the Firmware <a class="header-anchor" href="#_2-update-the-firmware" aria-label="Permalink to &quot;2. Update the Firmware&quot;">​</a></h3><p>Update the camera firmware to: <code>openipc-urlic-aio-nor</code></p><img src="'+t+'" alt="jumbo" width="800px"><hr><h3 id="_3-change-mtu-to-3994" tabindex="-1">3. Change MTU to 3994 <a class="header-anchor" href="#_3-change-mtu-to-3994" aria-label="Permalink to &quot;3. Change MTU to 3994&quot;">​</a></h3><p>Go to the <strong>WFB Settings</strong> tab and find the <code>MTU</code> parameter.</p><ul><li>▶️ Default value: <code>1500</code></li><li>▶️ Change to: <code>3994</code></li><li>✅ Click <strong>Save and Reboot</strong> to restart the device.</li></ul><img src="'+a+'" alt="jumbo1" width="800px"><hr><h3 id="_4-sensor-bin-file-for-improved-image-quality" tabindex="-1">4. Sensor Bin File for Improved Image Quality <a class="header-anchor" href="#_4-sensor-bin-file-for-improved-image-quality" aria-label="Permalink to &quot;4. Sensor Bin File for Improved Image Quality&quot;">​</a></h3><p>Use the <em>sensor bin file</em> from Greg to improve image sharpness.</p><ul><li>Go to <code>Setup → Bin File Update</code></li><li>Download the recommended file.</li></ul><img src="'+o+'" alt="jumbo2" width="800px"><hr><div class="info custom-block"><p class="custom-block-title">💡 Note</p><p>MTU value <code>3994</code> provides larger packet sizes, which reduces latency and improves video stream quality over Ethernet.</p></div><hr><h2 id="air-unit-overheating-protection" tabindex="-1">Air Unit Overheating Protection <a class="header-anchor" href="#air-unit-overheating-protection" aria-label="Permalink to &quot;Air Unit Overheating Protection&quot;">​</a></h2><ol><li>Open <code>/usr/bin/</code> on the Air Unit and upload the script.</li></ol><div class="info custom-block"><p class="custom-block-title">💡 Note</p><p>This script automatically checks the VTX and Wi-Fi adapter temperature and restarts the device in case of overheating.</p></div><hr><p><code>temperatura_check.sh</code> — <code>temperatura_check.sh</code></p><ol start="2"><li><strong>Then open <code>/etc/rc.local/</code> and add</strong> <code>temperatura_check &amp;</code></li></ol>',37)])])}const b=r(d,[["render",p]]);export{v as __pageData,b as default};
